class Solution {
    public int[] nextGreaterElements(int[] nums) {
        int n = nums.length;
        Deque<Integer> stack = new ArrayDeque<>();
        int ans[] = new int[n];

        for(int i = 2*n-1 ;i>=0;i--){
            int realIx = i%n;
            int num = nums[realIx];
            while(!stack.isEmpty() && num >= stack.peek()){
                stack.pop();
            }
            if(stack.isEmpty()) ans[realIx] = -1;
            else{
                ans[realIx] = stack.peek();
            }
            stack.push(num);
        }
        return ans;
    }
}

class Solution {
    public String removeKdigits(String num, int k) {
        int n = num.length();
        if(k==n)return "0";
        int removeCount = 0;

        Deque<Integer> stack = new ArrayDeque<>();
        for(int i = 0; i < n; i++){
            int number =num.charAt(i)-'0';
            while(!stack.isEmpty() && removeCount < k && number < stack.peek()){
                stack.pop();
                removeCount++;
            }
            stack.push(number);
        }
        while(!stack.isEmpty() && removeCount<k){
            stack.pop();
            removeCount++;
        }

        StringBuilder ans = new StringBuilder("");
        while(!stack.isEmpty()){
            ans.append(stack.pop());
        }
        ans.reverse();
        int start = 0;
        while (start < ans.length() - 1 && ans.charAt(start) == '0') {
            start++;
        }
        return ans.substring(start);
    }
}

class Solution {
    public int[] asteroidCollision(int[] asteroids) {
        int n = asteroids.length;
        Deque<Integer> stack = new ArrayDeque<>();
        outer:
        for(int i = 0; i < n; i++){
            while(!stack.isEmpty() && stack.peek()>0 && asteroids[i]<0){
                if(stack.peek()< Math.abs(asteroids[i])){
                    stack.pop();
                }else if(stack.peek() == Math.abs(asteroids[i])){
                    stack.pop();
                    continue outer;
                }else{
                    continue outer;
                }
            }

            stack.push(asteroids[i]);
        }
        int[] ans = new int[stack.size()];
        int ix = ans.length-1;
        while(!stack.isEmpty()){
            ans[ix] = stack.pop();
            ix--;
        }
        return ans;
    }
}

